import{_ as o,o as a,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Facebook Business Manager","description":"","frontmatter":{"title":"Facebook Business Manager","slug":"facebook-business-manager"},"headers":[],"relativePath":"marketer-hub/facebook-business-manager.md","filePath":"marketer-hub/facebook-business-manager.md"}'),t={name:"marketer-hub/facebook-business-manager.md"};function s(c,e,i,l,d,b){return a(),n("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Facebook Business Manager allows you to manage several Facebook Ad Accounts within a single dashboard.</p><div class="warning custom-block"><p class="custom-block-title">Required Permissions</p><p>You will need to be an Administrator on your Facebook Business Manager account.</p></div><h2 id="_1-enable-branch-on-your-facebook-dashboard" tabindex="-1">1. Enable Branch on your Facebook Dashboard <a class="header-anchor" href="#_1-enable-branch-on-your-facebook-dashboard" aria-label="Permalink to &quot;1. Enable Branch on your Facebook Dashboard&quot;">​</a></h2><ol><li><p>On your Facebook dashboard, select <strong>Events Manager</strong> &gt; <strong>Partner Integrations</strong>.</p></li><li><p>Select your Branch App.</p></li><li><p>Click <strong>Continue</strong> and follow the on-screen prompts to connect your Facebook Ad-account with Branch.</p></li></ol><h2 id="_2-retrieve-your-facebook-developers-app-id" tabindex="-1">2. Retrieve your Facebook Developers App ID <a class="header-anchor" href="#_2-retrieve-your-facebook-developers-app-id" aria-label="Permalink to &quot;2. Retrieve your Facebook Developers App ID&quot;">​</a></h2><ol><li><p>Go to the <a href="https://developers.facebook.com/" target="_blank" rel="noreferrer">Developers Facebook page</a>.</p></li><li><p>Select your App from the dropdown menu.</p></li><li><p>Navigate to <strong>Setting</strong> &gt; <strong>Basic</strong> and select the <strong>App ID</strong> &amp; <strong>Secret Key</strong> copy and paste these to the relevant section on the Branch dashboard.</p></li></ol><h2 id="_3-authorize-your-facebook-ad-account-and-business-manager" tabindex="-1">3. Authorize Your Facebook Ad Account and Business Manager <a class="header-anchor" href="#_3-authorize-your-facebook-ad-account-and-business-manager" aria-label="Permalink to &quot;3. Authorize Your Facebook Ad Account and Business Manager&quot;">​</a></h2><ol><li>Navigate to <strong>Advanced Settings</strong>.</li><li>Scroll down to the <strong>Access</strong> section.</li><li>Under the <strong>Business Manager</strong> and <strong>Facebook Ad-Accounts</strong> section enter the <strong>BM ID</strong> and the <strong>Facebook Ad-Account ID</strong>.</li></ol><h2 id="_4-check-settings-in-facebook-ads-manager" tabindex="-1">4. Check Settings in Facebook Ads Manager <a class="header-anchor" href="#_4-check-settings-in-facebook-ads-manager" aria-label="Permalink to &quot;4. Check Settings in Facebook Ads Manager&quot;">​</a></h2><ol><li>Navigate to <strong>Ad Account Settings</strong>.</li><li>Either via the access manager on your Facebook Ads Manager Dashboard or by clicking the gear icon on the top right corner of the screen.</li></ol><p>I3. In the <strong>Ad Account Setup</strong> window you will observe the Timezone and the attribution window of your ad account. If you are not able to see these options please contact Facebook Support</p><h2 id="_5-enable-facebook-in-your-branch-dashboard" tabindex="-1">5. Enable Facebook in Your Branch Dashboard <a class="header-anchor" href="#_5-enable-facebook-in-your-branch-dashboard" aria-label="Permalink to &quot;5. Enable Facebook in Your Branch Dashboard&quot;">​</a></h2><p>You can now enable Facebook as an Ad Partner in your Branch dashboard!</p><p>Please follow our guide for <a href="./facebook-app-install-ads.html">Facebook App Install Ads</a>.</p>',15)])])}const g=o(t,[["render",s]]);export{u as __pageData,g as default};
